import { describe, it, expect, beforeEach, jest } from '@jest/globals';
import express, { type Express } from 'express';
import request from 'supertest';

let capturedQueryText = '';
let capturedQueryParams: any[] = [];

const queryBuilder: any = {
  from: jest.fn().mockReturnThis(),
  innerJoin: jest.fn().mockReturnThis(),
  leftJoin: jest.fn().mockReturnThis(),
  where: jest.fn().mockImplementation(function (clause: any) {
    try {
      const sqlObj = clause?.queryChunks ? clause : clause;
      const parts: string[] = [];
      const params: any[] = [];
      const walk = (c: any) => {
        if (!c) return;
        if (Array.isArray(c)) return c.forEach(walk);
        if (c.queryChunks) return walk(c.queryChunks);
        if (c.value !== undefined && c.encoder) {
          params.push(c.value);
          parts.push('?');
          return;
        }
        if (typeof c === 'string') {
          parts.push(c);
          return;
        }
        if (c.name && c.table) {
          parts.push(`${c.table?.[Symbol.for('drizzle:Name')] ?? ''}.${c.name}`);
          return;
        }
        if (c.value !== undefined) {
          params.push(c.value);
          parts.push('?');
          return;
        }
        if (c.queryChunks === undefined && c.left && c.right) {
          walk(c.left);
          parts.push(c.operator ?? '');
          walk(c.right);
          return;
        }
      };
      walk(sqlObj);
      capturedQueryText = JSON.stringify(clause, (_k, v) => {
        if (typeof v === 'function') return '[fn]';
        return v;
      });
      capturedQueryParams = params;
    } catch (e) {
      capturedQueryText = String(clause);
    }
    return queryBuilder;
  }),
  orderBy: jest.fn().mockResolvedValue([]),
};

const mockDb: any = {
  select: jest.fn().mockImplementation(() => queryBuilder),
};

// First select() call returns user's accessible orgs
let selectCallCount = 0;
mockDb.select.mockImplementation(() => {
  selectCallCount++;
  if (selectCallCount === 1) {
    return {
      from: jest.fn().mockReturnValue({
        where: jest.fn().mockResolvedValue([{ organizationId: 'org-1' }]),
      }),
    };
  }
  return queryBuilder;
});

jest.mock('../../../server/db', () => ({ db: mockDb }));

jest.mock('../../../server/auth', () => ({
  requireAuth: (req: any, _res: any, next: any) => {
    req.user = currentTestUser;
    next();
  },
}));

jest.mock('../../../server/services/consolidated-communication-service', () => ({
  communicationService: {},
}));

let currentTestUser: any = null;

import { registerCommunicationRoutes } from '../../../server/api/communication';

function buildApp(user: any): Express {
  currentTestUser = user;
  const app = express();
  app.use(express.json());
  registerCommunicationRoutes(app);
  return app;
}

describe('REST GET /api/communication/general recipientRoles filter', () => {
  beforeEach(() => {
    selectCallCount = 0;
    capturedQueryText = '';
    capturedQueryParams = [];
  });

  it('admin call performs no recipientRoles filtering (no WHERE)', async () => {
    const app = buildApp({ id: 'u-admin', role: 'admin' });
    await request(app).get('/api/communication/general').expect(200);
    // Admin path doesn't go through the userOrgs lookup; it skips straight to
    // the unfiltered select. We assert the captured WHERE was never set.
    expect(capturedQueryText).toBe('');
  });

  it('tenant call WHERE clause includes IS NULL, cardinality=0, and user_organizations EXISTS subquery', async () => {
    const app = buildApp({ id: 'u-tenant', role: 'tenant' });
    await request(app).get('/api/communication/general').expect(200);
    const text = capturedQueryText.toLowerCase();
    expect(text).toContain('is null');
    expect(text).toContain('cardinality');
    expect(text).toContain('user_organizations');
    expect(text).toContain('organization_role');
    // The current user's id is bound as a parameter to the EXISTS subquery
    // (rather than relying on session.role), preventing global-role leaks.
    expect(capturedQueryParams).toContain('u-tenant');
  });

  it('manager call WHERE clause also uses per-org organization_role lookup', async () => {
    const app = buildApp({ id: 'u-manager', role: 'manager' });
    await request(app).get('/api/communication/general').expect(200);
    const text = capturedQueryText.toLowerCase();
    expect(text).toContain('user_organizations');
    expect(text).toContain('organization_role');
    expect(capturedQueryParams).toContain('u-manager');
  });
});
